''
// import React, { Children } from "react
import CurrencySelect from "./Dropdown";
import Image from "next/image";
import Link from "next/link";
import { ShoppingCart } from "lucide-react";
import { FaChevronDown, FaSearch } from "react-icons/fa";

export default function Header() {
  const navitmes = [
    {
      path: "/",
      name: "Home",
    },

    {
      path: "/about",
      name: "About Us",
    },

    {
      path: "/products",
      name: "Products",
    },

    {
      path: "/contact",
      name: "Contact Us",
    },
  ];
  console.log(navitmes);

  return (
    <>
      <header className="w-full ms-auto ">
        {/* top section   */}
        <div className="w-full py-3 px-6">
          <div className="w-full flex justify-between font items-center ">
            <div className="flex items-center  gap-5">
              <div className="px-2 py-1 rounded-md bg-[#EBEEF6] text-black">
                Hotline 24/7
              </div>
              <div className="font-semibold">(025) 3886 25 16</div>
            </div>
            <div className="flex items-center  gap-15">
              <div className="flex gap-5 ">
                <a href="">Sell on Ishop</a>
                <a href="">Order Tracking</a>
              </div>
              <div className="flex items-center gap-2  ">
                <select className="border-r h-6 border-gray-300 " name="" id="">
                  <option value="">USD</option>
                  <option value="">INR</option>
                  <option value="">YEN</option>
                  <option value="">EUR</option>
                </select>
               
              </div>
            </div>
          </div>
        </div>
        {/* nav section */}
        <div className="px-6 w-full mb-5 flex justify-between mt-4">
          {/* nav left section */}
          <div className="flex gap-20 items-center">
            <div className="flex gap-3 items-center">
              {/* logo */}
              <div className="relative">
                <Image
                  src="/logo/logo.png"
                  alt="Company logo"
                  width={55}
                  height={49}
                  priority
                />
                <div className="absolute inset-0 flex items-center justify-center">
                  <Image
                    src={"/logo/vector1.png"}
                    alt="vector"
                    width={15}
                    height={10}
                  />
                </div>
              </div>
              <a className="font-bold" href="">
                ISHOP
              </a>
            </div>
            <div className="flex gap-10 font-bold uppercase">
              {navitmes.map((itmes, index) => {
                return (
                  <Link key={index} href={itmes.path} className="">
                    {itmes.name}
                  </Link>
                );
              })}
            </div>
          </div>
          {/* nav right section */}

          <div className="flex items-center gap-20">
            {/* login / regisetr */}
            <div>
              <div className="text-gray-400">WELCOME</div>
              <div className="font-bold">
                <a href="">LOG IN / </a>
                <a href=""> REGISTER</a>
              </div>
            </div>
            {/* cart section */}
            <div className="flex items-center gap-5">
              <div className="relative inline-flex items-center justify-center">
                {/* Cart Icon */}
                <Link href={"/cart"}>
                <ShoppingCart className="w-6 h-6 text-gray-800" />

                </Link>

                {/* Badge */}
                <span className="absolute -top-2 -right-2 min-w-[18px] h-[18px] px-1 flex items-center justify-center text-[10px] font-semibold text-white bg-red-600 rounded-full leading-none shadow">
                  5
                </span>
              </div>
              <div>
                <p className="text-gray-400">CART</p>
                <p className="font-bold">$2422.00</p>
              </div>
            </div>
          </div>
        </div>
        {/* search section */}
        <div className="w-full">
          <div className="px-6 flex items-center w-full py-4 bg-[#01A49E] gap-6">
            {/* Search bar (will grow) */}
            <div className="rounded-4xl bg-white flex items-center flex-1 py-2 px-4 text-black gap-4">
              {/* Category */}
              <div className="flex items-center gap-2 whitespace-nowrap">
                <span>All Categories</span>
                <FaChevronDown className="text-gray-500" />
              </div>

              {/* Input */}
              <input
                className="flex-1 outline-none"
                type="text"
                placeholder="Search for Products, Brand & More"
              />

              {/* Search icon */}
              <FaSearch className="text-gray-500 cursor-pointer" />
            </div>

            {/* OUTSIDE elements (you can add more here) */}
            <ul className="flex text-white gap-20 ms-20 me-10 uppercase">
              <li>free shipping over $199</li>
              <li>30 days money back</li>
              <li>100% secure payment</li>
            </ul>
            {/* <a href="#" className="text-white whitespace-nowrap">
            </a>
            <a href="#" className="text-white whitespace-nowrap">
            </a>
            <a href="#" className="text-white whitespace-nowrap">
            </a> */}
          </div>
        </div>
      </header>
    </>
  );
}
